summary:
The issue in the application was a goroutine leak in the `/compute` HTTP handler. When a client disconnected before the intensive computation was complete, the goroutine performing that computation would continue running indefinitely because it didn't monitor the request context for cancellation.

I fixed this by:
1. Passing the request context (`r.Context()`) to the `performComputation` function.
2. Updating `performComputation` to periodically check `ctx.Done()` during its execution loop and sleep intervals.
3. Updating the `computeHandler` to use a `select` statement that listens for `ctx.Done()` to handle client disconnections or timeouts promptly.

The `test.sh` script now confirms that goroutines are correctly cleaned up after client disconnects.

```go
// In computeHandler
ctx := r.Context()
go func() {
    atomic.AddInt64(&activeGoroutines, 1)
    defer atomic.AddInt64(&activeGoroutines, -1)

    result, err := performComputation(ctx, req)
    if err == nil {
        resultCh <- result
    }
}()

select {
case result := <-resultCh:
    w.Header().Set("Content-Type", "application/json")
    json.NewEncoder(w).Encode(result)
case <-ctx.Done():
    return
case <-time.After(25 * time.Second):
    http.Error(w, "computation timed out", http.StatusGatewayTimeout)
}

// In performComputation
for i := 0; i < req.Iterations; i++ {
    select {
    case <-ctx.Done():
        return ComputeResult{}, ctx.Err()
    default:
    }
    // ... computation logic ...
    select {
    case <-ctx.Done():
        return ComputeResult{}, ctx.Err()
    case <-time.After(time.Duration(req.DelayMs) * time.Millisecond):
    }
}
```
